// Minimal printf mapped to UART output.
// Format: %d (decimal), %c (char), %x (hex), %s (string), %% (literal %).

#define NULL 0
#define EOF (-1)

#define _STDIO_UART_DATA   0xFF0100
#define _STDIO_UART_STATUS 0xFF0101

void _putc_uart(int ch) {
    while (*(char *)_STDIO_UART_STATUS & 0x80) {}
    *(char *)_STDIO_UART_DATA = ch;
}

int putchar(int ch) {
    _putc_uart(ch);
    return ch;
}

int getchar(void) {
    // Wait for UART RX ready (bit 0 of status register)
    while (!(*(char *)_STDIO_UART_STATUS & 0x01)) {}
    return *(char *)_STDIO_UART_DATA;
}

int getc(void) {
    return getchar();
}

int puts(char *s) {
    while (*s) {
        _putc_uart(*s);
        s = s + 1;
    }
    _putc_uart(10);
    return 0;
}

void _print_int(int n) {
    if (n < 0) {
        _putc_uart(45);
        n = 0 - n;
    }
    if (n == 0) {
        _putc_uart(48);
        return;
    }
    char buf[8];
    int i = 0;
    while (n > 0) {
        buf[i] = 48 + n % 10;
        n = n / 10;
        i++;
    }
    while (i > 0) {
        i--;
        _putc_uart(buf[i]);
    }
}

void _print_hex(int n) {
    if (n == 0) {
        _putc_uart(48);
        return;
    }
    char hex[6];
    int i = 0;
    while (n > 0) {
        int d = n & 15;
        if (d < 10) {
            hex[i] = 48 + d;
        } else {
            hex[i] = 87 + d;
        }
        n = n >> 4;
        i++;
    }
    while (i > 0) {
        i--;
        _putc_uart(hex[i]);
    }
}

